                // Assign the indices of the two numbers
                result[0] = j;
                result[1] = i;

                *returnSize = 2;
                return result;
            }
        }

        // If complement not found, add the current number and its index to the hashmap
        hashmap[i] = nums[i];
    }

    *returnSize = 0; // No solution found
    return NULL;
}

int main() {
    int nums[] = {2, 7, 11, 15};
    int target = 9;
    int numsSize = sizeof(nums) / sizeof(nums[0]);

    int returnSize;
    int* result = twoSum(nums, numsSize, target, &returnSize);

    printf("Indices of the two numbers that add up to target: %d %d\n", result[0], result[1]);

    free(result);

    return 0;
}
